def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = 0 if item == 0 else np.inf
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        if item == 0 and capacity > 0:
            priorities[i] = 0
            continue
        if ratio < 0:
            priorities[i] = np.inf
            continue
        score = 0.0
        penalty = 0.0
        decay = 1.0
        extra_penalties = 0.0
        modifier = 1.0
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 5:
            for k in range(1, 8):
                penalty += (ratio ** (3 * k)) / (k ** 4 + 1)
            for j in range(1, 6):
                decay *= (1 - 1 / (ratio + j + 3))
            score = (ratio ** 6) / 5 + penalty
            if item > capacity * 6:
                score *= 4
            else:
                score *= 3
            priorities[i] = score * decay * (1 + np.log(item+1))
        elif 4 < ratio <= 5:
            for x in range(1, 9):
                sign = (-1) ** (x + 1)
                score += sign * (ratio ** x) / (x + 3)
            for y in range(1, 6):
                decay *= (1 - 1 / (y + ratio + 4))
            score = abs(score) * decay * 15
            if ratio > 4.5:
                modifier += 0.5
            priorities[i] = score * modifier
        elif 2 < ratio <= 4:
            temp = 0
            for p in range(1, 15):
                if p % 3 == 0:
                    temp += (ratio ** p) / (p * 7)
                elif p % 2 == 0:
                    temp -= (ratio ** p) / (p * 5)
                else:
                    temp += (ratio ** p) / (p * 6)
            multiplier = 30 if ratio < 3 else 20 if ratio < 3.5 else 15
            score = abs(temp) * multiplier
            if ratio > 3.8:
                extra = 0
                for m in range(1, 8):
                    extra += (ratio ** m) / (m * 4 + 2)
                score += extra * 3
            priorities[i] = score
        elif 1 < ratio <= 2:
            temp_score = 0
            for p in range(1, 18):
                if p % 5 == 0:
                    temp_score += (ratio ** p) / (p * 4)
                elif p % 3 == 0:
                    temp_score -= (ratio ** p) / (p * 6)
                else:
                    temp_score += (ratio ** p) / (p * 7)
            multiplier = 27 if ratio < 1.3 else 20 if ratio < 1.6 else 13
            score = abs(temp_score) * multiplier
            if ratio > 1.8:
                extra_penalties = 0
                for n in range(1, 9):
                    extra_penalties += (ratio ** n) / (n + 2)
                score += extra_penalties * 4
            priorities[i] = score
        elif 0 < ratio <= 1:
            temp_score = 0
            for p in range(1, 20):
                if p % 6 == 0:
                    temp_score -= (ratio ** p) / (p * 5)
                elif p % 4 == 0:
                    temp_score += (ratio ** p) / (p * 4)
                elif p % 3 == 0:
                    temp_score -= (ratio ** p) / (p * 7)
                else:
                    temp_score += (ratio ** p) / (p * 6)
            if ratio < 0.15:
                multiplier = 35
            elif ratio < 0.35:
                multiplier = 25
            elif ratio < 0.55:
                multiplier = 18
            elif ratio < 0.75:
                multiplier = 10
            else:
                multiplier = 8
            score = abs(temp_score) * multiplier
            if ratio > 0.9:
                extra_penalties = 0
                for n in range(1, 10):
                    extra_penalties += (ratio ** n) / (n + 3)
                score += extra_penalties * 3
            priorities[i] = score
        else:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
        if priorities[i] != np.inf and bins[i] > 0:
            factor = 1.0
            for z in range(1, 6):
                factor *= (1 + z / (bins[i] + 2))
            for w in range(1, 4):
                factor *= (1 + (w ** 2) / (bins[i] + 3))
            priorities[i] *= factor
            if item > capacity / 2:
                priorities[i] *= 1.1
            else:
                priorities[i] *= 0.9
        elif bins[i] <= 0:
            priorities[i] = np.inf
    return priorities
